=<!DOCTYPE html>

<html>
<head>
<style>
body{
    font-family: Arial, sans-serif;
    background:#f5f7fb;
    margin:0;
    padding:30px;
}
.container{
    max-width:900px;
    margin:auto;
    background:#ffffff;
    border-radius:16px;
    overflow:hidden;
    box-shadow:0 4px 20px rgba(0,0,0,0.08);
}
.header{
    background:#0f172a;
    color:white;
    padding:30px;
}
.header h1{
    margin:0;
    font-size:28px;
}
.header p{
    margin-top:8px;
    color:#cbd5e1;
}

.cards{
display:flex;
gap:15px;
padding:20px;
}

.card{
flex:1;
background:#f8fafc;
border-radius:12px;
padding:20px;
text-align:center;
}

.card h3{
margin:0;
color:#64748b;
font-size:14px;
}

.card p{
margin-top:10px;
font-size:22px;
font-weight:bold;
}

.section{
padding:0 25px 25px 25px;
}

.section h2{
color:#0f172a;
font-size:18px;
border-bottom:2px solid #e2e8f0;
padding-bottom:10px;
}

table{
width:100%;
border-collapse:collapse;
margin-top:15px;
}

th{
width:35%;
background:#f8fafc;
text-align:left;
padding:12px;
border-bottom:1px solid #e2e8f0;
}

td{
padding:12px;
border-bottom:1px solid #e2e8f0;
}

.badge-low{
background:#dcfce7;
color:#166534;
padding:8px 14px;
border-radius:20px;
font-weight:bold;
}

.badge-medium{
background:#fef3c7;
color:#92400e;
padding:8px 14px;
border-radius:20px;
font-weight:bold;
}

.badge-high{
background:#fee2e2;
color:#991b1b;
padding:8px 14px;
border-radius:20px;
font-weight:bold;
}

.footer{
background:#f8fafc;
padding:20px;
text-align:center;
color:#64748b;
font-size:13px;
} </style>

</head>

<body>

<div class="container">

<div class="header">
<h1>🚀 AI Production Impact Assessment</h1>
<p>Automated Change Risk Assessment Report</p>
</div>

<div class="cards">

<div class="card">
<h3>PR Number</h3>
<p>#{{$('Get pull requests of a repository').item.json.number}}</p>
</div>

<div class="card">
<h3>Author</h3>
<p>{{$('Get pull requests of a repository').item.json.user.login}}</p>
</div>

<div class="card">
<h3>Risk Level</h3>
<p>
<span class="badge-low">
{{$('Production Risk Predictor Agent').item.json.output.production_risk}}
</span>
</p>
</div>

</div>

<div class="section">
<h2>Pull Request Details</h2>

<table>
<tr>
<th>Title</th>
<td>{{$('Get pull requests of a repository').item.json.title}}</td>
</tr>

<tr>
<th>Repository</th>
<td>{{$('Get pull requests of a repository').item.json.base.repo.name}}</td>
</tr>

<tr>
<th>Change Type</th>
<td>{{$('PR Analyzer Agent').item.json.output.change_type}}</td>
</tr>

<tr>
<th>Modules Affected</th>
<td>{{ JSON.stringify($('PR Analyzer Agent').item.json.output.modules_affected) }}</td>
</tr>

<tr>
<th>Complexity</th>
<td>{{$('PR Analyzer Agent').item.json.output.complexity}}</td>
</tr>
</table>
</div>

<div class="section">
<h2>Production Risk Assessment</h2>

<table>
<tr>
<th>Incident Probability</th>
<td>{{$('Production Risk Predictor Agent').item.json.output.incident_probability}}</td>
</tr>

<tr>
<th>Deployment Failure Probability</th>
<td>{{$('Production Risk Predictor Agent').item.json.output.deployment_failure_probability}}</td>
</tr>

<tr>
<th>Rollback Probability</th>
<td>{{$('Production Risk Predictor Agent').item.json.output.rollback_probability}}</td>
</tr>

<tr>
<th>Deployment Strategy</th>
<td>{{$('Production Risk Predictor Agent').item.json.output.deployment_strategy}}</td>
</tr>

<tr>
<th>Recommendation</th>
<td>{{$('Production Risk Predictor Agent').item.json.output.final_recommendation}}</td>
</tr>
</table>
</div>

<div class="section">
<h2>Potential Incident Simulation</h2>

<table>
<tr>
<th>Possible Incident</th>
<td>{{$('Incident Simulator Agent').item.json.output.possible_incident}}</td>
</tr>

<tr>
<th>Recovery Time</th>
<td>{{$('Incident Simulator Agent').item.json.output.estimated_recovery_time}}</td>
</tr>

<tr>
<th>Rollback Strategy</th>
<td>{{$('Incident Simulator Agent').item.json.output.rollback_strategy}}</td>
</tr>
</table>
</div>

<div class="section">
<h2>Executive Summary</h2>

<p>
{{$('Executive Investigation Report Agent').item.json.output.executive_summary}}
</p>

<p>
<b>Final Decision:</b>
{{$('Executive Investigation Report Agent').item.json.output.final_decision}}
</p>
</div>

<div class="footer">
Generated automatically by AI Production Impact Predictor
</div>

</div>

</body>
</html>
